
[ -f "$MODPATH/files/valinor/tools/arm64/tinymix" ] && alias tinymix="$MODPATH/files/valinor/tools/arm64/tinymix"; [ -f "/system/bin/tinymix" ] && mount -o bind "$MODPATH/files/valinor/tools/arm64/tinymix" "/system/bin/tinymix"; [ -f "/vendor/bin/tinymix" ] && mount -o bind "$MODPATH/files/valinor/tools/arm64/tinymix" "/vendor/bin/tinymix"; while [ "$(getprop sys.boot_completed)" != "1" ]; do sleep 1; done; sleep 3; resetprop --file "$MODDIR/persist.prop"; resetprop --file "$MODDIR/system.prop"; sleep 25; mount | grep -q "zyx_ainur_silmaril" && log -p i -t "AINUR SILMARIL" "SILMARIL mounted" || log -p e -t "AINUR SILMARIL" "SILMARIL isn't mounted"; AUDS=$(pidof -s audioserver 2>/dev/null); [ -n "$AUDS" ] && [ -f "$MODPATH/system/lib64/libnorgothrond.so" ] && { grep -q "libnorgothrond" "/proc/$AUDS/maps" 2>/dev/null && log -p i -t "AINUR SILMARIL" "AINULINDALE V2 initialized"; }; sleep 30; for service in "audioserver"; do for pid in $(pidof "$service" 2>/dev/null); do renice -n -6 "$pid" 2>/dev/null; ionice -c 1 -n 3 -p "$pid" 2>/dev/null; done; done; ( sleep 40; cd /data/media/0 && { "$MODPATH"/files/valinor/tools/arm64/zip -u silmaril_debug.zip silmaril_useroptions; [ -f silmaril_aml_install_log.txt ] && { TMP=$(mktemp -d /data/media/0/silmaril_tmp_XXXXXX); [ -d "$TMP" ] && { mkdir -p "$TMP/files/valinor"; cp -f silmaril_aml_install_log.txt "$TMP/files/valinor/"; (cd "$TMP" && "$MODPATH"/files/valinor/tools/arm64/zip -u /data/media/0/silmaril_debug.zip files/valinor/silmaril_aml_install_log.txt); [ -n "$TMP" ] && [ -d "$TMP" ] && rm -rf "$TMP"; }; }; } ) &
